mapper.select:
select id, type, sceneinfo, frontmoney, money, queenmoney, createtime, appid, orderid, logid,notes
from moneylog m
where AppId = #{appId}

    and Id=#{id}


    and Type=#{type}


    and SceneInfo=#{sceneInfo}


    and m.CreateTime >= #{startCreateTime}


    and m.CreateTime <= #{endCreateTime}


    and OrderId=#{orderId}


    and Money=#{money}

order by CreateTime desc

    limit ${rowIndex},${limit}

select count(Id) from moneylog m
where AppId = #{appId}

    and Id=#{id}


    and Type=#{type}


    and SceneInfo=#{sceneInfo}


    and m.CreateTime >= #{startCreateTime}


    and m.CreateTime <= #{endCreateTime}


    and OrderId=#{orderId}


    and Money=#{money}

select id, type, sceneinfo, frontmoney, money, queenmoney, createtime, appid, orderid, logid
from moneylog m
where AppId = #{appId}

    and Id=#{id}


    and Type=#{type}


    and SceneInfo=#{sceneInfo}


    and m.CreateTime >= #{startCreateTime}


    and m.CreateTime <= #{endCreateTime}


    and OrderId=#{orderId}


    and Money=#{money}

order by id desc
